import org.junit.jupiter.api.Test;

class CascadesCostModelTest {

	@Test
	void filterCallsProviderAndPreservesIntervalConfidence() {
		TrackingProvider provider = new TrackingProvider();
		CascadesCostModel model = model(provider);
		Filter filter = new Filter(pattern("s", "p1", "o"), new Bound(new Var("o")));

		LogicalProperties properties = model.logicalProperties(filter);

		assertEquals(1, provider.filterCalls);
		assertEquals(2.0d, properties.estimatedRows());
		assertEquals(0.80d, properties.qErrorInterval().confidence());
	}

	@Test
	void joinWithStatementPatternFactorsUsesMultiPatternProvider() {
		TrackingProvider provider = new TrackingProvider();
		CascadesCostModel model = model(provider);
		Join join = new Join(pattern("s", "p1", "o1"), pattern("s", "p2", "o2"));

		LogicalProperties properties = model.logicalProperties(join);

		assertEquals(1, provider.multiPatternCalls);
		assertEquals(7.0d, properties.estimatedRows());
	}

	@Test
	void leftJoinAndDifferenceKeepConservativeRowBounds() {
		CascadesCostModel model = model(new TrackingProvider());
		StatementPattern left = pattern("s", "p1", "o1");
		StatementPattern right = pattern("s", "p2", "o2");

		LogicalProperties leftJoin = model.logicalProperties(new LeftJoin(left, right));
		LogicalProperties difference = model.logicalProperties(new Difference(left, right));

		assertTrue(leftJoin.estimatedRows() >= 20.0d);
		assertTrue(difference.estimatedRows() <= 20.0d);
	}

	@Test
	void differenceWithoutSharedVariablesKeepsLeftRows() {
		CascadesCostModel model = model(new TrackingProvider());
		StatementPattern left = pattern("left", "p1", "leftObject");
		StatementPattern right = pattern("right", "p2", "rightObject");

		LogicalProperties difference = model.logicalProperties(new Difference(left, right));

		assertEquals(20.0d, difference.estimatedRows(), 0.0d,
				"SPARQL MINUS without shared variables must keep all left rows");
	}

	@Test
	void localCostUsesStandardOptimizationEstimatorTier() {
		RecordingFactorCostModel factorCostModel = new RecordingFactorCostModel();
		CascadesCostModel model = new CascadesCostModel.DefaultCascadesCostModel(new EvaluationStatistics(),
				factorCostModel, new TrackingProvider());
		MemoExpr expression = new MemoExpr(1, 7, "StatementPattern", List.of(), "", pattern("s", "p1", "o"),
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);

		model.localCost(expression, OptimizationGoal.root(), List.of());

		assertEquals(List.of(EstimationTier.STANDARD), factorCostModel.estimationTiers);
	}

	@Test
	void joinEstimateDoesNotTreatOptionalOnlyLeftBindingAsBound() {
		TrackingProvider provider = new TrackingProvider(false);
		CascadesCostModel model = model(provider);
		StatementPattern mandatoryLeft = pattern("s", "required", "requiredValue");
		StatementPattern optionalLeft = pattern("s", "optional", "maybe");
		StatementPattern right = pattern("maybe", "right", "value");

		model.logicalProperties(new Join(new LeftJoin(mandatoryLeft, optionalLeft), right));

		assertFalse(provider.rightPatternBoundVars.isEmpty(), "Expected the test provider to observe the JOIN RHS");
		assertTrue(provider.rightPatternBoundVars.stream().noneMatch(boundVars -> boundVars.contains("maybe")),
				"JOIN RHS estimates must not inherit nullable OPTIONAL bindings as assured bound variables: "
						+ provider.rightPatternBoundVars);
	}

	@Test
	void localCostDoesNotPromoteInputOutputBindingsToExternalBindings() {
		TrackingProvider provider = new TrackingProvider(false);
		CascadesCostModel model = model(provider);
		StatementPattern mandatoryLeft = pattern("s", "required", "requiredValue");
		StatementPattern optionalLeft = pattern("s", "optional", "maybe");
		LeftJoin left = new LeftJoin(mandatoryLeft, optionalLeft);
		StatementPattern right = pattern("maybe", "right", "value");
		Join join = new Join(left, right);
		MemoExpr expression = new MemoExpr(1, 7, "Join", List.of(2, 3), "", join, PhysicalProperties.ANY,
				RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);

		model.localCost(expression, OptimizationGoal.root(), List.of(winner(2, left), winner(3, right)));

		assertFalse(provider.rightPatternBoundVars.isEmpty(), "Expected local cost to estimate the JOIN RHS");
		assertTrue(provider.rightPatternBoundVars.stream()
				.noneMatch(boundVars -> boundVars.contains("maybe") || boundVars.contains("value")),
				"JOIN local cost must not treat input output variables as external bindings: "
						+ provider.rightPatternBoundVars);
	}

	private static CascadesCostModel model(RdfStatisticsProvider provider) {
		return new CascadesCostModel.DefaultCascadesCostModel(new EvaluationStatistics(), null, provider);
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static Winner winner(int groupId, TupleExpr plan) {
		MemoExpr expression = new MemoExpr(groupId, groupId, plan.getClass().getSimpleName(), List.of(), "", plan,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		PhysicalProperties delivered = PhysicalProperties.builder()
				.boundVars(plan.getBindingNames())
				.build();
		return new Winner(expression, plan, delivered, CostVector.ZERO, List.of(), false, "");
	}

	private static final class TrackingProvider implements RdfStatisticsProvider {
		private int filterCalls;
		private int multiPatternCalls;
		private final List<Set<String>> rightPatternBoundVars = new java.util.ArrayList<>();
		private final boolean provideMultiPattern;

		private TrackingProvider() {
			this(true);
		}

		private TrackingProvider(boolean provideMultiPattern) {
			this.provideMultiPattern = provideMultiPattern;
		}

		@Override
		public Optional<StatisticsEstimate> statementPattern(StatementPattern pattern, Set<String> boundVars) {
			if ("right".equals(pattern.getPredicateVar().getName())) {
				rightPatternBoundVars.add(boundVars == null ? Set.of() : Set.copyOf(boundVars));
			}
			double rows = pattern.getPredicateVar().getName().equals("p1") ? 20.0d : 5.0d;
			return Optional.of(StatisticsEstimate.exact(rows, "test-statement"));
		}

		@Override
		public Optional<StatisticsEstimate> filter(TupleExpr input, ValueExpr condition,
				StatisticsEstimate inputEstimate, Set<String> boundVars) {
			filterCalls++;
			EstimateVector vector = inputEstimate.vector()
					.filter(0.10d,
							QErrorInterval.fromBounds(0.05d, 0.10d, 0.20d, 0.80d, "test-filter"),
							"test-filter");
			return Optional.of(StatisticsEstimate.fromVector(vector, "test-filter"));
		}

		@Override
		public Optional<StatisticsEstimate> multiPatternJoin(List<TupleExpr> orderedFactors, Set<String> boundVars) {
			multiPatternCalls++;
			if (!provideMultiPattern) {
				return Optional.empty();
			}
			return Optional.of(StatisticsEstimate.heuristic(7.0d, "test-multi-pattern"));
		}
	}

	private static final class RecordingFactorCostModel implements JoinFactorCostModel {
		private final List<EstimationTier> estimationTiers = new java.util.ArrayList<>();

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			return Optional.empty();
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, CostContext context) {
			estimationTiers.add(context.getEstimationTier());
			return Optional.of(new FactorCostEstimate(2.0d, 1.0d, Map.of(), Map.of()));
		}
	}
}
